import { useState, useEffect, useRef, useCallback } from "react";

const STAR_PATH = "M 100,5 C 101,44 148,99 195,100 C 148,101 101,156 100,195 C 99,156 52,101 5,100 C 52,99 99,44 100,5 Z";

function StarIcon({ size = 80 }) {
  return (
    <div style={{ width: size, height: size, flexShrink: 0 }}>
      <svg viewBox="0 0 200 200" style={{ width: '100%', height: '100%', overflow: 'visible' }}>
        <defs>
          <filter id="star-glow" x="-40%" y="-40%" width="180%" height="180%">
            <feGaussianBlur in="SourceGraphic" stdDeviation="6" result="blur"/>
            <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
          </filter>
        </defs>
        <path fill="#FF8F53" filter="url(#star-glow)" d={STAR_PATH} />
      </svg>
    </div>
  );
}

function ChartBlock({ chart }) {
  const canvasRef = useRef(null);
  const instanceRef = useRef(null);
  const color = chart.color || '#FF8F53';
  const type = chart.type || 'bar';
  const isLine = type === 'line';
  const isPie = type === 'pie' || type === 'doughnut';
  const isRadar = type === 'radar';
  const isScatter = type === 'scatter';

  useEffect(() => {
    const load = () => {
      if (!canvasRef.current || !window.Chart) return;
      if (instanceRef.current) instanceRef.current.destroy();
      const ctx = canvasRef.current.getContext('2d');
      let data = {};

      if (isPie) {
        const colors = [color, '#64C4A0', '#7F77DD', '#EF9F27', '#E86A5A', '#5BB8D4'];
        data = { labels: chart.labels, datasets: [{ data: chart.values, backgroundColor: chart.labels.map((_, i) => colors[i % colors.length] + 'CC'), borderColor: '#0A0A0A', borderWidth: 2 }] };
      } else if (isRadar) {
        data = { labels: chart.labels, datasets: [{ data: chart.values, backgroundColor: color + '22', borderColor: color, borderWidth: 2, pointBackgroundColor: color, pointRadius: 4 }] };
      } else if (isScatter) {
        const points = chart.labels.map((x, i) => ({ x: parseFloat(x), y: chart.values[i] }));
        data = { datasets: [{ data: points, backgroundColor: color + 'AA', borderColor: color, pointRadius: 5, pointHoverRadius: 7 }] };
      } else {
        const maxVal = Math.max(...chart.values);
        let bgColor = color + '18';
        if (isLine) { const grad = ctx.createLinearGradient(0,0,0,180); grad.addColorStop(0, color+'55'); grad.addColorStop(1, color+'00'); bgColor = grad; }
        data = { labels: chart.labels, datasets: [{ data: chart.values, backgroundColor: isLine ? bgColor : chart.values.map(v => v===maxVal ? color : color+'55'), borderColor: color, borderWidth: isLine ? 2 : 0, borderRadius: isLine ? 0 : 6, borderSkipped: false, pointBackgroundColor: chart.values.map(v => v===maxVal ? color : color+'AA'), pointBorderColor: '#0A0A0A', pointBorderWidth: 2, pointRadius: isLine ? 4 : 0, pointHoverRadius: isLine ? 6 : 0, fill: isLine, tension: 0.45 }] };
      }

      instanceRef.current = new window.Chart(ctx, {
        type: isScatter ? 'scatter' : type,
        data,
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { display: isPie || isRadar, labels: { color: '#9C9890', font: { size: 11 } } },
            tooltip: { backgroundColor: '#1A1A18', titleColor: '#F0EDE8', bodyColor: '#9C9890', borderColor: 'rgba(255,255,255,0.08)', borderWidth: 1 }
          },
          scales: isPie || isRadar ? (isRadar ? { r: { grid: { color: 'rgba(255,255,255,0.06)' }, ticks: { display: false }, pointLabels: { color: '#9C9890', font: { size: 10 } } } } : {}) : {
            x: { grid: { display: false }, border: { display: false }, ticks: { color: '#6B6860', font: { size: 10 } }, title: chart.xLabel ? { display: true, text: chart.xLabel, color: '#6B6860', font: { size: 10 } } : { display: false } },
            y: { grid: { color: 'rgba(255,255,255,0.04)' }, border: { display: false }, ticks: { color: '#6B6860', font: { size: 10 }, callback: v => v >= 1000 ? (v/1000).toFixed(1)+'k' : v }, title: chart.yLabel ? { display: true, text: chart.yLabel, color: '#6B6860', font: { size: 10 } } : { display: false } }
          }
        }
      });
    };
    if (window.Chart) load();
    else { const s = document.createElement('script'); s.src = 'https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.js'; s.onload = load; document.head.appendChild(s); }
    return () => { if (instanceRef.current) instanceRef.current.destroy(); };
  }, [chart]);

  const maxVal = chart.values ? Math.max(...chart.values) : 0;
  const maxIdx = chart.values ? chart.values.indexOf(maxVal) : 0;
  const growth = chart.values && chart.values.length > 1 ? Math.round(((chart.values[maxIdx] - chart.values[0]) / chart.values[0]) * 100) : null;

  return (
    <div className="chart-block">
      <div className="chart-header">
        <div className="chart-title">{chart.title}</div>
        {!isPie && !isRadar && growth !== null && (
          <div className="chart-peak">
            <span className="chart-peak-val">{maxVal >= 1000 ? (maxVal/1000).toFixed(1)+'k' : maxVal}</span>
            {growth !== 0 && <span className="chart-peak-growth" style={{color: growth > 0 ? '#64C4A0' : '#E86A5A'}}>{growth > 0 ? '+' : ''}{growth}%</span>}
          </div>
        )}
      </div>
      <div style={{position:'relative', height: isPie || isRadar ? 200 : 160}}>
        <canvas ref={canvasRef} />
      </div>
    </div>
  );
}

export default function BingoDemo() {
  const [stage, setStage] = useState("input");
  const [query, setQuery] = useState("");
  const [selected, setSelected] = useState([]);
  const [scanData, setScanData] = useState(null);
  const [revealed, setRevealed] = useState(new Set());
  const [synthesis, setSynthesis] = useState("");
  const [synthDone, setSynthDone] = useState(false);
  const [error, setError] = useState(null);
  const [exampleIdx, setExampleIdx] = useState(0);
  const [lazyOverride, setLazyOverride] = useState(null);
  const [tooltip, setTooltip] = useState(null);
  const [modeTooltip, setModeTooltip] = useState(false);
  const [projectMeta, setProjectMeta] = useState({ name:"", topic:"", goal:"", notes:"" });
  const [analyticsMeta, setAnalyticsMeta] = useState("");
  const [charts, setCharts] = useState([]);
  const hoverTimer = useRef(null);
  const modeHoverTimer = useRef(null);

  const peripheral = DOMAINS.filter(d => !selected.includes(d));
  const autoLazy = selected.length >= 1 && !isSameCluster(selected);
  const lazyMode = lazyOverride !== null ? lazyOverride : autoLazy;

  useEffect(() => {
    const t = setInterval(() => setExampleIdx(i => (i+1) % EXAMPLE_QUERIES.length), 3200);
    return () => clearInterval(t);
  }, []);

  const toggleDomain = (d) => {
    setSelected(prev => prev.includes(d) ? prev.filter(x => x !== d) : prev.length < 4 ? [...prev, d] : prev);
  };

  // Separate API call just for charts — no delimiter issues
  const fetchCharts = async (proseText) => {
    try {
      const res = await fetch("https://bngo.onrender.com/api/charts", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ proseText, analyticsMeta }),
      });
      const data = await res.json();
      if (Array.isArray(data.charts)) setCharts(data.charts.filter(c => c.labels && c.values && c.labels.length === c.values.length));
    } catch {}
  };

  const runDirectSynthesis = async () => {
    try {
      const isProject = selected.includes("Project");
      const res = await fetch("https://bngo.onrender.com/api/synthesis/direct", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ query, selected, isProject, projectMeta }),
      });
      const data = await res.json();
      const text = data.text || "";
      const words = text.split(" ");
      for (let i = 0; i < words.length; i++) {
        await new Promise(r => setTimeout(r, 28));
        setSynthesis(prev => prev + (i > 0 ? " " : "") + words[i]);
      }
      setSynthDone(true);
      if (selected.includes("Analytics")) await fetchCharts(text);
    } catch (e) { setSynthDone(true); }
  };

  const runPhase1 = async () => {
    if (query.trim().length < 3 || selected.length < 1) return;
    setError(null);
    setCharts([]);
    if (!lazyMode) {
      setStage("synthesis");
      setSynthesis("");
      setSynthDone(false);
      setScanData({ scans:[], winner:null });
      await runDirectSynthesis();
      return;
    }
    setStage("scanning");
    setRevealed(new Set());
    setScanData(null);
    try {
      const res = await fetch("https://bngo.onrender.com/api/phase1", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ query, selected, peripheral }),
      });
      const parsed = await res.json();
      if (parsed.error) throw new Error(parsed.error);
      setScanData(parsed);
      for (let i = 0; i < parsed.scans.length; i++) {
        await new Promise(r => setTimeout(r, 300 + i * 650));
        setRevealed(prev => new Set([...prev, parsed.scans[i].domain]));
      }
      await new Promise(r => setTimeout(r, 1200));
      setStage("pick");
    } catch (e) {
      setError("Something went wrong. Try again.");
      setStage("input");
    }
  };

  const runSynthesis = async () => {
    if (!scanData?.winner) return;
    setStage("synthesis");
    setSynthesis("");
    setSynthDone(false);
    try {
      const isProject = selected.includes("Project");
      const res = await fetch("https://bngo.onrender.com/api/synthesis", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ query, selected, winner: scanData.winner, isProject, projectMeta }),
      });
      const data = await res.json();
      const text = data.text || "";
      const words = text.split(" ");
      for (let i = 0; i < words.length; i++) {
        await new Promise(r => setTimeout(r, 28));
        setSynthesis(prev => prev + (i > 0 ? " " : "") + words[i]);
      }
      setSynthDone(true);
      if (selected.includes("Analytics")) await fetchCharts(text);
    } catch (e) { setSynthDone(true); }
  };

  const pickWinner = (domain) => {
    const scan = scanData.scans.find(s => s.domain === domain);
    setScanData(prev => ({
      ...prev,
      winner: { domain, angle: scan?.angle || "", teaser: prev.winner?.domain === domain ? prev.winner.teaser : prev.winner?.teaser || "" }
    }));
    setStage("teaser");
  };

  const reset = () => {
    setStage("input");
    setQuery("");
    setSelected([]);
    setScanData(null);
    setRevealed(new Set());
    setSynthesis("");
    setSynthDone(false);
    setError(null);
    setLazyOverride(null);
    setProjectMeta({ name:"", topic:"", goal:"", notes:"" });
    setCharts([]);
    setAnalyticsMeta("");
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display:ital@0;1&family=Instrument+Sans:wght@400;500;600&family=DM+Mono:wght@400;500&family=Cormorant+Garamond:ital,wght@0,400;0,600;1,400;1,600&display=swap');
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
        :root{
          --bg:#0A0A0A;--s1:#121212;--s2:#1A1A1A;
          --border:rgba(255,255,255,0.08);--border-md:rgba(255,255,255,0.14);
          --accent:#FF8F53;--accent-dim:rgba(255,143,83,0.12);
          --text:#F0EDE8;--muted:#6B6860;--mid:#9C9890;--green:#64C4A0;
          --serif:'DM Serif Display',Georgia,serif;
          --sans:'Instrument Sans',system-ui,sans-serif;
          --mono:'DM Mono','Fira Mono',monospace;
        }
        .app{min-height:100vh;background:var(--bg);color:var(--text);font-family:var(--sans);display:flex;flex-direction:column;align-items:center;}
        .topbar{width:100%;max-width:860px;padding:24px 32px;display:flex;align-items:center;justify-content:space-between;}
        .topbar-brand{display:flex;align-items:center;gap:8px;}
        .topbar-logo{height:42px;width:auto;display:block;}
        .topbar-name{font-family:var(--serif);font-size:20px;letter-spacing:-0.01em;color:var(--text);}
        .topbar-dot{color:var(--accent);font-style:normal;}
        .topbar-right{display:flex;align-items:center;gap:14px;}
        .chip{font-family:var(--mono);font-size:9px;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);border:1px solid var(--border);padding:4px 10px;border-radius:100px;}
        .inspired{font-family:var(--mono);font-size:9px;color:var(--muted);letter-spacing:0.06em;}
        .divider{width:100%;max-width:860px;height:1px;background:var(--border);}
        .main{width:100%;max-width:720px;padding:56px 24px 80px;display:flex;flex-direction:column;align-items:center;}

        /* INPUT */
        .input-stage{width:100%;display:flex;flex-direction:column;}
        .pro-corner{display:inline-flex;align-items:center;gap:8px;padding:7px 18px 7px 14px;border:1px solid rgba(255,143,83,0.22);border-radius:100px;margin-bottom:28px;align-self:center;}
        .pro-corner-logo{height:22px;width:auto;display:block;}
        .pro-corner-text{font-family:var(--mono);font-size:13px;font-weight:500;letter-spacing:0.2em;text-transform:uppercase;color:rgba(255,143,83,0.55);}
        .headline{font-family:var(--serif);font-size:44px;line-height:1.12;letter-spacing:-0.025em;text-align:center;margin-bottom:10px;}
        .subline{font-size:15px;color:var(--mid);text-align:center;line-height:1.65;margin-bottom:48px;}
        .query-box{width:100%;background:var(--s1);border:1px solid var(--border);border-radius:14px;padding:18px 20px;font-family:var(--sans);font-size:16px;color:var(--text);line-height:1.65;outline:none;resize:none;min-height:88px;transition:border-color 0.2s;margin-bottom:10px;}
        .query-box::placeholder{color:var(--muted);}
        .query-box:focus{border-color:rgba(255,143,83,0.5);}
        .example-hint{font-size:12px;color:var(--muted);font-family:var(--mono);margin-bottom:36px;height:16px;overflow:hidden;font-style:italic;}
        .dl{font-family:var(--mono);font-size:10px;color:var(--muted);letter-spacing:0.1em;text-transform:uppercase;margin-bottom:12px;}
        .pills{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:16px;}
        .pill{display:flex;align-items:center;gap:7px;padding:9px 16px;border:1px solid var(--border);border-radius:100px;background:transparent;color:var(--mid);font-family:var(--sans);font-size:13px;font-weight:500;cursor:pointer;transition:all 0.18s;}
        .pill:hover{border-color:var(--border-md);color:var(--text);}
        .pill.on{border-color:var(--accent);color:var(--accent);background:var(--accent-dim);}
        .pill .sym{font-size:11px;opacity:0.65;}

        /* Analytics hint */
        .analytics-hint{display:flex;align-items:center;gap:8px;padding:9px 14px;border:1px solid rgba(100,196,160,0.18);border-radius:100px;background:rgba(100,196,160,0.04);margin-bottom:6px;animation:pfade 0.25s cubic-bezier(0.22,1,0.36,1) forwards;}
        .analytics-hint-text{font-family:var(--mono);font-size:10px;letter-spacing:0.06em;color:var(--muted);flex:1;}
        .analytics-hint-btn{font-family:var(--mono);font-size:10px;letter-spacing:0.08em;color:var(--green);background:rgba(100,196,160,0.1);border:1px solid rgba(100,196,160,0.3);border-radius:100px;padding:3px 10px;cursor:pointer;transition:all 0.18s;white-space:nowrap;}
        .analytics-hint-btn:hover{background:rgba(100,196,160,0.2);border-color:rgba(100,196,160,0.5);}

        /* Analytics panel */
        .analytics-panel{border:1px solid rgba(100,196,160,0.2);border-radius:12px;background:rgba(100,196,160,0.03);padding:14px 18px;margin-bottom:8px;animation:pfade 0.28s cubic-bezier(0.22,1,0.36,1) forwards;}

        /* Project panel */
        .project-panel{border:1px solid var(--border);border-radius:12px;background:var(--s1);padding:16px 18px;margin-bottom:12px;animation:pfade 0.28s cubic-bezier(0.22,1,0.36,1) forwards;}
        @keyframes pfade{from{opacity:0;transform:translateY(-6px);}to{opacity:1;transform:translateY(0);}}
        .project-panel-header{display:flex;align-items:center;gap:8px;margin-bottom:14px;}
        .project-panel-icon{font-size:13px;color:var(--accent);opacity:0.7;}
        .project-panel-title{font-size:12px;font-weight:600;color:var(--text);letter-spacing:0.01em;flex:1;}
        .project-panel-opt{font-family:var(--mono);font-size:9px;color:var(--muted);letter-spacing:0.1em;border:1px solid var(--border);padding:2px 8px;border-radius:100px;}
        .project-fields{display:flex;flex-direction:column;gap:8px;}
        .project-input{width:100%;background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:9px 13px;font-family:var(--sans);font-size:13px;color:var(--text);outline:none;transition:border-color 0.18s;resize:none;display:block;}
        .project-input::placeholder{color:var(--muted);}
        .project-input:focus{border-color:rgba(255,143,83,0.4);}
        .project-textarea{line-height:1.6;}

        /* Lazy toggle */
        .lazy-toggle-row{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;border:1px solid var(--border);border-radius:10px;margin-bottom:12px;background:var(--s1);}
        .lazy-toggle-info{display:flex;flex-direction:column;gap:2px;position:relative;}
        .lazy-toggle-label{font-size:13px;font-weight:500;color:var(--text);}
        .lazy-toggle-sub{font-family:var(--mono);font-size:9px;color:var(--muted);letter-spacing:0.08em;}
        .lazy-toggle-btn{font-family:var(--mono);font-size:10px;color:var(--muted);background:transparent;border:1px solid var(--border);border-radius:6px;padding:5px 12px;cursor:pointer;letter-spacing:0.06em;transition:all 0.18s;}
        .lazy-toggle-btn:hover{border-color:var(--border-md);color:var(--text);}
        .mode-tooltip{position:absolute;bottom:calc(100% + 12px);left:0;background:#161616;border:1px solid rgba(255,143,83,0.2);border-radius:14px;padding:16px 18px;font-family:var(--sans);font-size:12px;color:var(--mid);line-height:1.65;width:270px;white-space:normal;pointer-events:none;z-index:99;animation:tipIn 0.2s cubic-bezier(0.22,1,0.36,1) forwards;}
        .mt-header{display:flex;align-items:center;gap:6px;margin-bottom:9px;padding-bottom:9px;border-bottom:1px solid rgba(255,255,255,0.06);}
        .mt-title{font-family:var(--mono);font-size:9px;font-weight:500;letter-spacing:0.14em;text-transform:uppercase;color:var(--text);}
        .mt-body{margin:0 0 10px;color:var(--mid);font-size:12px;line-height:1.65;}
        .mt-note{font-family:var(--mono);font-size:10px;color:var(--muted);letter-spacing:0.04em;line-height:1.5;padding-top:8px;border-top:1px solid rgba(255,255,255,0.05);}
        .mode-tooltip em{color:var(--accent);font-style:normal;}

        .go-btn{width:100%;padding:15px;background:var(--accent);border:none;border-radius:10px;color:#0A0A0A;font-family:var(--sans);font-size:15px;font-weight:600;cursor:pointer;letter-spacing:0.01em;transition:opacity 0.18s,transform 0.15s;}
        .go-btn:hover{opacity:0.88;transform:translateY(-1px);}
        .go-btn:disabled{opacity:0.25;cursor:not-allowed;transform:none;}
        .err{font-size:13px;color:#E07070;margin-top:14px;text-align:center;font-family:var(--mono);}

        /* Domain tooltip */
        .domain-tooltip{position:fixed;transform:translate(-50%,-100%);background:#1C1C1C;border:1px solid rgba(255,143,83,0.35);border-radius:8px;padding:9px 14px;pointer-events:none;z-index:999;animation:tipIn 0.18s cubic-bezier(0.22,1,0.36,1) forwards;white-space:nowrap;}
        @keyframes tipIn{from{opacity:0;transform:translate(-50%,calc(-100% + 6px));}to{opacity:1;transform:translate(-50%,calc(-100% - 4px));}}
        .dt-model{font-family:var(--mono);font-size:11px;font-weight:500;color:var(--accent);letter-spacing:0.06em;margin-bottom:2px;}
        .dt-note{font-family:var(--mono);font-size:9px;color:var(--muted);letter-spacing:0.08em;}
        .pro-badge-inline{font-family:var(--mono);font-size:8px;font-weight:600;letter-spacing:0.12em;color:#0A0A0A;background:var(--accent);padding:2px 6px;border-radius:3px;margin-left:4px;vertical-align:middle;}
        .pro-badge-phase{font-family:var(--mono);font-size:7px;font-weight:600;letter-spacing:0.14em;color:#0A0A0A;background:var(--accent);padding:2px 6px;border-radius:3px;margin-left:6px;vertical-align:middle;opacity:0.9;}

        /* SCANNING */
        .scan-stage{width:100%;display:flex;flex-direction:column;align-items:center;}
        .scan-phase-label{font-family:var(--mono);font-size:9px;color:var(--muted);letter-spacing:0.18em;text-transform:uppercase;margin-bottom:36px;display:flex;align-items:center;gap:10px;}
        .scan-phase-label::before,.scan-phase-label::after{content:'';width:28px;height:1px;background:var(--border);}
        .scan-query-display{font-family:var(--serif);font-style:italic;font-size:19px;color:var(--mid);text-align:center;line-height:1.55;max-width:500px;margin-bottom:48px;}
        .scan-active-pills{display:flex;gap:6px;flex-wrap:wrap;justify-content:center;margin-bottom:44px;}
        .scan-active-pill{display:flex;align-items:center;gap:6px;padding:5px 13px;border:1px solid var(--border);border-radius:100px;font-size:12px;font-weight:500;color:var(--text);position:relative;}
        .scan-active-pill::before{content:'';width:4px;height:4px;border-radius:50%;background:var(--accent);animation:pdot 2s ease infinite;flex-shrink:0;}
        @keyframes pdot{0%,100%{opacity:1}50%{opacity:0.2}}
        .scan-divider{width:100%;max-width:560px;height:1px;background:var(--border);margin-bottom:8px;}
        .scan-list{width:100%;max-width:560px;}
        .scan-row{display:flex;align-items:flex-start;gap:16px;padding:16px 0;border-bottom:1px solid var(--border);transition:opacity 0.4s;animation:rowIn 0.35s cubic-bezier(0.22,1,0.36,1) both;}
        @keyframes rowIn{from{opacity:0;transform:translateY(8px);}to{opacity:1;transform:translateY(0);}}
        .scan-row.skip{opacity:0.28;}
        .scan-row-left{display:flex;flex-direction:column;align-items:center;gap:6px;width:44px;flex-shrink:0;padding-top:2px;}
        .scan-row-indicator{width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;border:1px solid var(--border);color:var(--muted);transition:all 0.35s;flex-shrink:0;}
        .scan-row-indicator.yes{border-color:rgba(100,196,160,0.6);color:var(--green);background:rgba(100,196,160,0.07);}
        .scan-row-indicator.bing{border-color:var(--accent);color:var(--accent);background:var(--accent-dim);}
        .scan-row-right{flex:1;}
        .scan-row-name{display:flex;align-items:center;justify-content:space-between;margin-bottom:5px;}
        .scan-row-name-text{font-size:14px;font-weight:600;color:var(--text);letter-spacing:-0.01em;}
        .tag{font-family:var(--mono);font-size:9px;letter-spacing:0.1em;padding:3px 9px;border-radius:100px;}
        .tag.yes{background:rgba(100,196,160,0.12);color:var(--green);}
        .tag.skip{background:rgba(255,255,255,0.04);color:var(--muted);}
        .tag.bing{background:rgba(255,143,83,0.15);color:var(--accent);}
        .scan-row-angle{font-size:13px;color:var(--mid);line-height:1.6;font-style:italic;}
        .scan-row-angle.bing-angle{color:rgba(255,143,83,0.8);font-style:normal;}
        .spinner{width:12px;height:12px;border:1.5px solid var(--border);border-top-color:var(--muted);border-radius:50%;animation:spin 0.75s linear infinite;}
        @keyframes spin{to{transform:rotate(360deg);}}
        .scan-waiting-row{display:flex;align-items:center;gap:16px;padding:16px 0;border-bottom:1px solid var(--border);opacity:0.3;}
        .scan-waiting-dot{width:28px;height:28px;border-radius:50%;border:1px solid var(--border);flex-shrink:0;}
        .scan-waiting-line{height:1px;flex:1;background:var(--border);border-radius:1px;}

        /* PICK */
        .pick-stage{width:100%;display:flex;flex-direction:column;align-items:center;}
        .pick-phase-label{font-family:var(--mono);font-size:9px;color:var(--muted);letter-spacing:0.18em;text-transform:uppercase;margin-bottom:28px;display:flex;align-items:center;gap:10px;}
        .pick-phase-label::before,.pick-phase-label::after{content:'';width:28px;height:1px;background:var(--border);}
        .pick-query{font-family:var(--serif);font-style:italic;font-size:17px;color:var(--mid);text-align:center;margin-bottom:40px;max-width:480px;}
        .pick-prompt{font-family:var(--sans);font-size:13px;color:var(--muted);text-align:center;margin-bottom:24px;letter-spacing:0.01em;}
        .pick-list{width:100%;max-width:560px;display:flex;flex-direction:column;gap:8px;margin-bottom:32px;}
        .pick-card{display:flex;align-items:flex-start;gap:14px;padding:16px 18px;border:1px solid var(--border);border-radius:12px;background:var(--s1);cursor:pointer;transition:all 0.22s;text-align:left;}
        .pick-card:hover{border-color:rgba(255,143,83,0.45);background:var(--accent-dim);transform:translateY(-1px);}
        .pick-card-sym{font-size:14px;opacity:0.5;padding-top:2px;flex-shrink:0;}
        .pick-card-body{flex:1;}
        .pick-card-name{font-size:13px;font-weight:600;color:var(--text);margin-bottom:4px;}
        .pick-card-angle{font-size:12px;color:var(--mid);line-height:1.55;font-style:italic;}
        .pick-card-arrow{font-size:14px;color:var(--muted);padding-top:2px;flex-shrink:0;transition:transform 0.2s,color 0.2s;}
        .pick-card:hover .pick-card-arrow{transform:translateX(3px);color:var(--accent);}
        .pick-auto{font-family:var(--mono);font-size:10px;color:var(--muted);letter-spacing:0.08em;cursor:pointer;text-decoration:underline;text-underline-offset:3px;opacity:0.6;transition:opacity 0.2s;}
        .pick-auto:hover{opacity:1;}

        /* TEASER */
        .teaser-stage{width:100%;display:flex;flex-direction:column;align-items:center;animation:tfade 0.7s cubic-bezier(0.22,1,0.36,1) forwards;}
        @keyframes tfade{from{opacity:0;transform:translateY(32px);}to{opacity:1;transform:translateY(0);}}
        .teaser-anim-wrap{margin-bottom:0;display:flex;flex-direction:column;align-items:center;}
        .o-bingo-title{font-family:var(--serif);font-size:88px;color:var(--accent);letter-spacing:-0.04em;line-height:0.9;margin-bottom:32px;text-align:center;}
        .winner-tag{display:inline-flex;align-items:center;gap:8px;font-family:'Cormorant Garamond',Georgia,serif;font-size:17px;font-style:italic;color:rgba(255,143,83,0.7);margin-bottom:36px;letter-spacing:0.02em;}
        .teaser-text{font-family:var(--sans);font-style:normal;font-size:17px;font-weight:400;color:var(--text);line-height:1.7;max-width:500px;text-align:center;margin:0 auto 48px;opacity:0.85;}
        .reveal-btn{display:inline-flex;align-items:center;gap:10px;padding:13px 28px;background:transparent;border:1px solid rgba(255,143,83,0.5);border-radius:100px;color:var(--accent);font-family:var(--mono);font-size:11px;font-weight:500;letter-spacing:0.1em;text-transform:uppercase;cursor:pointer;transition:all 0.22s;}
        .reveal-btn:hover{background:var(--accent-dim);border-color:var(--accent);transform:translateY(-1px);}

        /* SYNTHESIS */
        .synth-stage{width:100%;}
        .synth-chips{display:flex;gap:7px;flex-wrap:wrap;margin-bottom:32px;padding-bottom:24px;border-bottom:1px solid var(--border);}
        .d-chip{font-family:var(--mono);font-size:10px;padding:4px 10px;border-radius:100px;border:1px solid var(--border);color:var(--muted);letter-spacing:0.06em;}
        .d-chip.win{border-color:rgba(255,143,83,0.5);color:var(--accent);background:var(--accent-dim);}
        .synth-body{font-size:16px;line-height:1.9;color:var(--text);width:100%;}
        .synth-body p{margin-bottom:22px;}
        .synth-h1{font-family:var(--serif);font-size:28px;font-weight:400;letter-spacing:-0.02em;color:var(--text);margin:36px 0 16px;line-height:1.2;}
        .synth-h2{font-family:var(--sans);font-size:13px;font-weight:600;letter-spacing:0.1em;text-transform:uppercase;color:var(--accent);opacity:0.75;margin:32px 0 10px;}
        .cursor{display:inline-block;width:2px;height:18px;background:var(--accent);margin-left:2px;vertical-align:middle;animation:blink 1s step-end infinite;}
        @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
        .bonus-marker{display:flex;flex-direction:column;align-items:center;gap:0;margin-top:40px;padding-top:40px;border-top:1px solid var(--border);width:100%;}
        .bonus-header{display:flex;flex-direction:column;align-items:center;gap:10px;margin-bottom:36px;width:100%;}
        .bonus-domain-name{font-family:var(--mono);font-size:11px;font-weight:500;font-style:normal;letter-spacing:0.18em;text-transform:uppercase;color:var(--accent);opacity:0.65;}
        .bonus-text{font-family:var(--sans);font-style:normal;font-size:16px;font-weight:400;line-height:1.85;color:var(--text);text-align:center;max-width:540px;padding:28px 36px;border:1px solid rgba(255,143,83,0.3);border-radius:16px;}
        .back-btn{margin-top:44px;display:inline-flex;align-items:center;gap:6px;padding:10px 20px;background:transparent;border:1px solid var(--border);border-radius:8px;color:var(--muted);font-family:var(--sans);font-size:13px;cursor:pointer;transition:all 0.18s;}
        .back-btn:hover{border-color:var(--border-md);color:var(--text);}
      `}</style>

      <div className="app">
        <div className="topbar">
          <div className="topbar-brand">
            <img src="data:image/png;base64," alt="o.Bingo" className="topbar-logo" />
            <span className="topbar-name">o<em className="topbar-dot">.</em>Bingo</span>
          </div>
          <div className="topbar-right">
            <span className="chip">Lazy Thinking™</span>
            <span className="inspired">Inspired by Claude</span>
          </div>
        </div>
        <div className="divider" />

        <main className="main">

          {/* INPUT */}
          {stage === "input" && (
            <div className="input-stage">
              <div className="pro-corner">
                <img src="data:image/png;base64," alt="o.Bingo" className="pro-corner-logo" />
                <svg width="16" height="16" viewBox="0 0 200 200" fill="none" style={{flexShrink:0}}>
                  <path fill="#FF8F53" fillOpacity="0.6" d="M 100,5 C 101,44 148,99 195,100 C 148,101 101,156 100,195 C 99,156 52,101 5,100 C 52,99 99,44 100,5 Z" />
                </svg>
                <span className="pro-corner-text">Pro</span>
              </div>

              <h1 className="headline">Ask anything.<br/>Discover the<br/><em style={{fontStyle:"italic",color:"var(--accent)"}}>unexpected.</em></h1>
              <p className="subline">Select your domains. Bingo scans the rest — silently —<br/>and surfaces the one insight you didn't think to ask for.</p>

              <textarea className="query-box" placeholder="What are you thinking about?" value={query} onChange={e => setQuery(e.target.value)} rows={3} />
              <div className="example-hint">e.g. "{EXAMPLE_QUERIES[exampleIdx]}"</div>

              <div className="dl">Select domains (1–4)</div>
              <div className="pills">
                {DOMAINS.map(d => (
                  <button key={d} className={`pill${selected.includes(d) ? " on" : ""}`}
                    onClick={() => toggleDomain(d)}
                    onMouseEnter={e => {
                      const rect = e.currentTarget.getBoundingClientRect();
                      hoverTimer.current = setTimeout(() => setTooltip({ domain:d, x:rect.left+rect.width/2, y:rect.top-8 }), 2000);
                    }}
                    onMouseLeave={() => { clearTimeout(hoverTimer.current); setTooltip(null); }}
                  >
                    <span className="sym">{DOMAIN_CONFIG[d].symbol}</span>{d}
                  </button>
                ))}
              </div>

              {selected.includes("Analytics") && !selected.includes("DeepSearch") && (
                <div className="analytics-hint">
                  <svg width="11" height="11" viewBox="0 0 200 200" fill="none" style={{flexShrink:0,marginTop:1}}>
                    <path fill="#78D4B4" fillOpacity="0.8" d="M 100,5 C 101,44 148,99 195,100 C 148,101 101,156 100,195 C 99,156 52,101 5,100 C 52,99 99,44 100,5 Z" />
                  </svg>
                  <span className="analytics-hint-text">For live data &amp; real numbers — add</span>
                  <button className="analytics-hint-btn" onClick={() => setSelected(prev => [...prev, "DeepSearch"])}>+ DeepSearch</button>
                </div>
              )}

              {selected.includes("Analytics") && (
                <div className="analytics-panel">
                  <div className="project-panel-header">
                    <span className="project-panel-icon" style={{color:"var(--green)"}}>◱</span>
                    <span className="project-panel-title">Chart preferences</span>
                    <span className="project-panel-opt">optional</span>
                  </div>
                  <textarea className="project-input project-textarea"
                    placeholder='e.g. "Show views and subscribers growth, also chart earnings over time"'
                    value={analyticsMeta} onChange={e => setAnalyticsMeta(e.target.value)} rows={2} />
                </div>
              )}

              {selected.includes("Project") && (
                <div className="project-panel">
                  <div className="project-panel-header">
                    <span className="project-panel-icon">◫</span>
                    <span className="project-panel-title">Project context</span>
                    <span className="project-panel-opt">optional</span>
                  </div>
                  <div className="project-fields">
                    <input className="project-input" placeholder="Project name" value={projectMeta.name} onChange={e => setProjectMeta(p => ({...p,name:e.target.value}))} />
                    <input className="project-input" placeholder="Topic" value={projectMeta.topic} onChange={e => setProjectMeta(p => ({...p,topic:e.target.value}))} />
                    <input className="project-input" placeholder="Goal" value={projectMeta.goal} onChange={e => setProjectMeta(p => ({...p,goal:e.target.value}))} />
                    <textarea className="project-input project-textarea"
                      placeholder='Preferences — e.g. "Use scientific language"'
                      value={projectMeta.notes} onChange={e => setProjectMeta(p => ({...p,notes:e.target.value}))} rows={2} />
                  </div>
                </div>
              )}

              <div className="lazy-toggle-row">
                <div className="lazy-toggle-info" style={{position:'relative'}}
                  onMouseEnter={() => { modeHoverTimer.current = setTimeout(() => setModeTooltip(true), 1000); }}
                  onMouseLeave={() => { clearTimeout(modeHoverTimer.current); setModeTooltip(false); }}
                >
                  <span className="lazy-toggle-label">
                    {lazyMode ? <>✦ Lazy Thinking <span className="pro-badge-inline">Pro</span></> : "◎ Focused mode"}
                  </span>
                  <span className="lazy-toggle-sub">
                    {lazyOverride === null
                      ? (lazyMode ? (selected.length === 1 ? "auto-detected · single domain" : "auto-detected · different domains") : "auto-detected · same field")
                      : "set manually"}
                  </span>
                  {modeTooltip && (
                    <div className="mode-tooltip">
                      {lazyMode ? (
                        <>
                          <div className="mt-header">
                            <svg width="11" height="11" viewBox="0 0 200 200" fill="none" style={{flexShrink:0,marginTop:1}}>
                              <path fill="#FF8F53" d="M 100,5 C 101,44 148,99 195,100 C 148,101 101,156 100,195 C 99,156 52,101 5,100 C 52,99 99,44 100,5 Z" />
                            </svg>
                            <span className="mt-title">Lazy Thinking Pro</span>
                          </div>
                          <p className="mt-body">Quietly scans peripheral domains in parallel. Surfaces one unexpected cross-domain insight — the <em>O, Bingo!</em> moment — only when it's genuinely surprising.</p>
                          <div className="mt-note">⏱ May take a moment longer — but might surprise you.</div>
                        </>
                      ) : (
                        <>
                          <div className="mt-header">
                            <span style={{fontSize:11,opacity:0.5}}>◎</span>
                            <span className="mt-title">Focused mode</span>
                          </div>
                          <p className="mt-body">Synthesizes directly from your selected domains. No detours, no cross-domain search — pure, rigorous depth.</p>
                          <div className="mt-note">⚡ Fastest response. Best for precise, technical questions.</div>
                        </>
                      )}
                    </div>
                  )}
                </div>
                <button className="lazy-toggle-btn"
                  onClick={() => setLazyOverride(lazyOverride === null ? !lazyMode : (lazyOverride ? false : null))}>
                  {lazyMode ? "Turn off" : "Turn on"}
                </button>
              </div>

              <button className="go-btn" onClick={runPhase1} disabled={query.trim().length < 3 || selected.length < 1}>
                {lazyMode ? "Run Lazy Thinking Pro →" : "Synthesize →"}
              </button>
              {error && <div className="err">{error}</div>}
            </div>
          )}

          {/* SCANNING */}
          {stage === "scanning" && (
            <div className="scan-stage">
              <div className="scan-phase-label">phase 01 · lazy thinking <span className="pro-badge-phase">Pro</span></div>
              <div className="scan-query-display">"{query}"</div>
              <div className="scan-active-pills">
                {selected.map(d => (
                  <div key={d} className="scan-active-pill">
                    <span style={{fontSize:11,opacity:0.6}}>{DOMAIN_CONFIG[d].symbol}</span>{d}
                  </div>
                ))}
              </div>
              <div className="scan-divider" />
              <div className="scan-list">
                {peripheral.map((d, i) => {
                  const isRevealed = revealed.has(d);
                  const scan = scanData?.scans?.find(s => s.domain === d);
                  const isWinner = scanData?.winner?.domain === d;
                  const stateKey = isWinner ? "bing" : scan?.relevant ? "yes" : "skip";
                  if (!isRevealed) return (
                    <div key={d} className="scan-waiting-row">
                      <div className="scan-waiting-dot" />
                      <span style={{fontSize:13,color:'var(--muted)',fontWeight:600}}>{d}</span>
                      <div className="scan-waiting-line" />
                      <span className="spinner" />
                    </div>
                  );
                  return (
                    <div key={d} className={`scan-row${stateKey==="skip"?" skip":""}`} style={{animationDelay:`${i*60}ms`}}>
                      <div className="scan-row-left">
                        <div className={`scan-row-indicator ${stateKey}`}>
                          {stateKey==="bing" ? "✦" : stateKey==="yes" ? "+" : "–"}
                        </div>
                      </div>
                      <div className="scan-row-right">
                        <div className="scan-row-name">
                          <span className="scan-row-name-text">{d}</span>
                          <span className={`tag ${stateKey}`}>{stateKey==="bing"?"BINGO":stateKey==="yes"?"YES":"SKIP"}</span>
                        </div>
                        {scan?.angle && <div className={`scan-row-angle${stateKey==="bing"?" bing-angle":""}`}>{scan.angle}</div>}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* PICK */}
          {stage === "pick" && scanData && (() => {
            const relevantDomains = scanData.scans.filter(s => s.relevant);
            const autoWinner = scanData.winner;
            return (
              <div className="pick-stage">
                <div className="pick-phase-label">phase 02 · your turn <span className="pro-badge-phase">Pro</span></div>
                <div className="pick-query">"{query}"</div>
                <p className="pick-prompt">Which angle surprises you most?</p>
                <div className="pick-list">
                  {(relevantDomains.length > 0 ? relevantDomains : [autoWinner]).map(s => (
                    <button key={s.domain} className="pick-card" onClick={() => pickWinner(s.domain)}>
                      <span className="pick-card-sym">{DOMAIN_CONFIG[s.domain]?.symbol}</span>
                      <div className="pick-card-body">
                        <div className="pick-card-name">{s.domain}</div>
                        <div className="pick-card-angle">{s.angle}</div>
                      </div>
                      <span className="pick-card-arrow">→</span>
                    </button>
                  ))}
                </div>
                <span className="pick-auto" onClick={() => pickWinner(autoWinner.domain)}>or let Bingo decide →</span>
              </div>
            );
          })()}

          {/* TEASER */}
          {stage === "teaser" && scanData?.winner && (
            <div className="teaser-stage">
              <div className="teaser-anim-wrap"><StarIcon size={120} /></div>
              <div className="o-bingo-title">O, Bingo!</div>
              <div className="winner-tag">{scanData.winner.domain}</div>
              <p className="teaser-text">{scanData.winner.teaser}</p>
              <button className="reveal-btn" onClick={runSynthesis}>Reveal the full insight <span style={{fontSize:14}}>→</span></button>
            </div>
          )}

          {/* SYNTHESIS */}
          {stage === "synthesis" && (
            <div className="synth-stage">
              <div className="synth-chips">
                {selected.map(d => <span key={d} className="d-chip">{d}</span>)}
                {scanData?.winner && <span className="d-chip win">{DOMAIN_CONFIG[scanData.winner.domain]?.symbol} {scanData.winner.domain}</span>}
              </div>
              <div className="synth-body">
                {(() => {
                  const paras = synthesis.split("\n\n").filter(p => p.trim());
                  const isProject = selected.includes("Project");
                  return paras.map((p, i) => {
                    const isLast = i === paras.length - 1 && paras.length > 1;
                    if (isLast && synthDone && scanData?.winner) {
                      return (
                        <div key={i} className="bonus-marker">
                          <div className="bonus-header">
                            <StarIcon size={96} />
                            <span className="bonus-domain-name">{scanData?.winner?.domain}</span>
                          </div>
                          <div className="bonus-text">{p.trim()}</div>
                        </div>
                      );
                    }
                    const trimmed = p.trim();
                    if (isProject && trimmed.startsWith("## ")) return <h2 key={i} className="synth-h2">{trimmed.replace(/^## /,"")}</h2>;
                    if (isProject && trimmed.startsWith("# ")) return <h1 key={i} className="synth-h1">{trimmed.replace(/^# /,"")}</h1>;
                    return <p key={i}>{trimmed}{!synthDone && i===paras.length-1 && <span className="cursor" />}</p>;
                  });
                })()}
                {!synthDone && synthesis.split("\n\n").filter(p=>p.trim()).length===0 && <span className="cursor" />}
              </div>
              {synthDone && charts.length > 0 && (
                <div style={{width:'100%',marginTop:8}}>
                  {charts.map((c,i) => <ChartBlock key={i} chart={c} />)}
                </div>
              )}
              {synthDone && <button className="back-btn" onClick={reset}>← New query</button>}
            </div>
          )}

        </main>

        {tooltip && (() => {
          const cfg = DOMAIN_CONFIG[tooltip.domain];
          return (
            <div className="domain-tooltip" style={{left:tooltip.x,top:tooltip.y}}>
              <div className="dt-model">{cfg.model}</div>
              <div className="dt-note">{cfg.modelNote}</div>
            </div>
          );
        })()}
      </div>
    </>
  );
}
